  scwin.blno = $c.util.isEmpty($p, $c.data.getParameter($p, "blno")) ? "" : $c.data.getParameter($p, "blno");
  scwin.intendDt = $c.util.isEmpty($p, $c.data.getParameter($p, "intendDt")) ? "" : $c.data.getParameter($p, "intendDt");
